class Solution:
    def checkArray(self, nums: List[int], k: int) -> bool:
        n = len(nums)
        diff = [0] * (n + 1)  # Difference array to track decrements
        decrements = 0  # Total decrements applied so far

        for i in range(n):
            decrements += diff[i]
            current = nums[i] - decrements

            if current < 0:
                return False

            if i + k <= n:
                # Apply decrement to subarray starting at i
                decrements += current
                diff[i + k] -= current

        return True
